import { Component } from '@angular/core';
import { FormArray, FormBuilder, FormGroup, Validators  } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';
import { catchError } from 'rxjs';
@Component({
  selector: 'app-categorydetails',
  templateUrl: './categorydetails.component.html',
  styleUrls: ['./categorydetails.component.scss']
})
export class CategorydetailsComponent {

  categoryForm: FormGroup;
  category: any;
  imageDynamicUrl: string;
  store_id: string;
  category_id: string;
  isLoading: boolean = true;
  storeName: string = '';

  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router
    ){

      this.categoryForm = this.fb.group({
        'store_id': ['', [Validators.required]],
         'category_id': ['',[Validators.required]],
         'parent_category_id': [null,[]],
         'is_featured_category': [false, [Validators.required]],
        'category_name': ['', [Validators.required]],
        'image_url': ['', []]

      })

    this.route.params.subscribe((p: any) => {
      this.store_id = p.store_id;
      this.category_id = p.category_id;
      this.getStoreDetails()
      this.getCategoryDetails()
    })
  }

  ngOnInit() {
    
  }


  getCategoryDetails() {
    const subscription = this.api.categoryDetail(this.store_id, this.category_id).subscribe((response: any) => {
      this.isLoading = false;
      subscription.unsubscribe();
      const category : any = response.category
      console.log(category)
      this.category = {
        store_id: this.store_id,
        category_id: this.category_id,
        parent_category_id: null,
        is_featured_category: category.is_featured_category,
        category_name: category.category_name,
        image_url: category.image.orignal_url
      }
      this.imageDynamicUrl = category.image.dynamic_url;
      this.categoryForm.setValue(this.category)
    })
  }

  deleteCategory() {
    const sub = this.api.deleteCategory(this.store_id, this.category_id)
    .pipe(
      catchError(err => {
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/categories']);
    })
  }

  updateCategory(){

    if(!this.categoryForm.valid) {
      return this.toastr.error("Please fill required fields")
    }

    const store_id = this.categoryForm.value.store_id;
    const category_id = this.categoryForm.value.category_id;
    const parent_category_id = this.categoryForm.value.parent_category_id;
    const is_featured_category = this.categoryForm.value.is_featured_category;
    const category_name = this.categoryForm.value.category_name;
    const image_url=this.categoryForm.value.image_url;
    const sub = this.api.updateCategory(this.store_id, category_id, parent_category_id, is_featured_category, category_name, image_url)  
    .pipe(
      catchError(err => {
        sub.unsubscribe();
        this.toastr.error(err.message);
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      if(response.status > 400) {
        this.toastr.error(response.error.message);
      }
      this.toastr.success(response?.message);
    })
  }

  fileUpload(files: File[]) {
    this.isLoading = true;
    const sub = this.api.uploadSingleFile(files[0]).subscribe((response: any) => {
      sub.unsubscribe();
      this.isLoading = false;
      this.categoryForm.controls.image_url.setValue(response.urls.orignal_url);
      this.imageDynamicUrl = response.urls.dynamic_url;
    })
  }

  getStoreDetails() {
    const sub = this.api.getStoreDetails(this.store_id).subscribe((response: any) => {
      sub.unsubscribe();
      this.storeName = response.store.store_name
    })
  }

}

