import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { ToastrService } from 'ngx-toastr';
import { catchError, debounceTime, delay, tap } from 'rxjs';
@Component({
  selector: 'app-createcategory',
  templateUrl: './createcategory.component.html',
  styleUrls: ['./createcategory.component.scss']
})
export class CreatecategoryComponent implements OnInit {

  categoryForm: FormGroup;
  isLoading = false;
  imageUrl: string;

  storeForm: FormGroup;
  storeList: Store[] = [];
  selectedStore : Store;

  category: any;
  imageDynamicUrl: string;
  store_id: string;
  category_id: string;
  storeName: string = '';
  

  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router
  ){
    this.categoryForm = this.fb.group({
      parent_category_id: [null, []],
      is_featured_category: [false, [Validators.required]],
      category_name: ['', [Validators.required]],
      image_url: ['', [Validators.required]]
    })

    this.storeForm = this.fb.group({
      store_id: ['', [Validators.required]],
      store_name: ['', [Validators.required]]
    })

    
  }

  ngOnInit() {
    this.storeForm.valueChanges.pipe(
      delay(500),
      tap(() => {
        const {store_id, store_name} = this.storeForm.value;
        this.listStores(store_name)
      })
    ).subscribe()
    this.listStores("")
  }


  listStores(store_name: string) {
    const sub = this.api.listStores(store_name, 1, 100, 'store_name', 'DESC').subscribe((response: any) => {
      sub.unsubscribe()
      this.storeList = response.stores.map((store) => {
        const {store_id, store_name} = store;
        return {store_id, store_name};
      })
    })
  }

  setStore(store: Store) {
    this.selectedStore = store;
  }

  fileUpload(files: File[]) {
    this.isLoading = true;
    const sub = this.api.uploadSingleFile(files[0]).subscribe((response: any) => {
      sub.unsubscribe();
      this.isLoading = false;
      this.categoryForm.controls.image_url.setValue(response.urls.orignal_url);
      this.imageDynamicUrl = response.urls.dynamic_url;
    })
  }


  createCategory() {

    if(!this.categoryForm.valid || !this.selectedStore) {
      return alert("Please fill all details")
    }

    const {parent_category_id, is_featured_category, category_name, image_url} = this.categoryForm.value;
    const sub = this.api.createCategory(this.selectedStore.store_id, parent_category_id, is_featured_category, category_name, image_url)
    .pipe(
      catchError(err => {
        sub.unsubscribe();
        this.toastr.error(err.message);
        return err;
      })
    )
    .subscribe((response: any) => {
      sub.unsubscribe();
      this.toastr.success(response?.message);
      this.router.navigate(['/categories'])
    })
  }


}













interface Store {
  store_id: string;
  store_name: string;
}