import { Component, ViewChild } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { delay, map, merge, startWith, switchMap, tap } from 'rxjs';
import { ApiService } from '@services/api.service';

@Component({
  selector: 'app-categorylist',
  templateUrl: './categorylist.component.html',
  styleUrls: ['./categorylist.component.scss']
})
export class CategorylistComponent {

  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  displayedColumns: string[] = ['category_id', 'category_name', 'Store Name', 'Total Products', 'Action'];
  data : Category[] = [];
  resultsLength = 0;
  sortBy: string = 'category_id'
  stores: string[] = [];

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;

  ngOnInit(): void {

  }
  
  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      q: ['', ]
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      delay(1000)
    ).subscribe(() => {
      this.api.categoryList(this.query, this.paginator.pageIndex + 1, this.paginator.pageSize, this.sort.active, this.sort.direction, this.stores).subscribe((data: any) => {
        this.isLoadingResults = false;
        if (data === null) {
          return [];
        }
  
        this.resultsLength = data.total_count;
        this.data = data.categories.map((categories:any) => {
          return {
            store_id: categories.store.store_id,
            category_id: categories.category_id,
            store_name: categories.store.store_name,
            category_name: categories.category_name,
            total_products: categories.total_products
          }
        });
      })
    })

  }

 
  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.categoryList(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction, this.stores);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.categories.map((categories:any) => {
            console.log(categories)
            return {
              store_id: categories.store.store_id,
              category_id: categories.category_id,
              store_name: categories.store.store_name,
              category_name: categories.category_name,
              total_products: categories.total_products
            }
          });
        }),
      )
      .subscribe(data => this.data = data);

  }

}

export interface Category {
  store_id: string,
  category_id: string,
  store_name: string,
  category_name: string,
  total_products: string
}